def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        priority = 0.0
        ratio = item / capacity
        if ratio < 0.25:
            acc = 0
            for x in range(1, 15):
                term = ((-1)**(x+1)) * (ratio**(x*3)) * (np.tan(x * 0.25))
                if x % 3 == 0:
                    term *= np.exp(-x * ratio * 0.5)
                acc += term
            priority += abs(acc) * 3.7
            mods = [3, 5, 7, 11]
            additions = [2.1, -1.3, 0.9, 1.6]
            mod_applied = False
            for m, add in zip(mods, additions):
                if capacity % m == 0:
                    priority += add
                    mod_applied = True
                    break
            if not mod_applied:
                priority -= 0.9
            if capacity > item * 20:
                for y in range(3, 10):
                    root = ratio ** (1.0 / y)
                    sign = (-1) ** (y + 1)
                    priority += sign * root * np.sqrt(y) * 1.4
            if priority > 70:
                priority = 70 + np.sqrt(np.log(priority - 69)**3 + 1)
        elif 0.25 <= ratio <= 0.75:
            base = 0
            for a in range(1, 8):
                base += ((-1)**(a)) * (np.cos(ratio * a * np.pi / 2)) * (a * 1.1)
                if a == 5 and capacity > item * 8:
                    base += 4.7
            priority += base
            if capacity < item * 1.1:
                priority *= 4.0
            elif capacity < item * 1.8:
                priority *= 2.5
            log_term = np.log(capacity + 2.5) - np.log(item + 0.7)
            if log_term > 0:
                priority += 10 / log_term
            else:
                priority += 30
            mod_vals = [2, 4, 10]
            mod_adds = [1.8, 1.2, 0.5]
            mod_flagged = False
            for modi, addv in zip(mod_vals, mod_adds):
                if capacity % modi == 0:
                    priority += addv
                    mod_flagged = True
                    break
            if not mod_flagged:
                priority -= 0.7
            if priority < 0:
                priority = 0
        elif 0.75 < ratio <= 1.25:
            priority = (ratio - 0.75)**2 * 200 + 35
            for b in range(1, 8):
                val = np.exp(-ratio * b * 0.9) * np.sin(np.pi * b * ratio / 2) * (b * 1.5)
                priority += val
            mods1 = [3, 6, 9]
            mods2 = [2.7, 3.5, 1.9]
            mod_found = False
            for m, add in zip(mods1, mods2):
                if capacity % m == 0:
                    priority += add
                    mod_found = True
                    break
            if not mod_found:
                priority += 0.3
            if capacity > item * 4:
                priority += 3.3
        elif 1.25 < ratio < 2:
            priority = (ratio - 1.25) * 220 + 55
            for c in range(1, 10):
                priority += ((-1) ** c) * np.sqrt(c * capacity) / (c + 3) * 1.1
            if capacity % 5 == 0:
                priority -= 2.3
            if capacity > item * 7:
                priority -= 3.5
            for d in range(2, 6):
                if (capacity // d) % 2 == 0:
                    priority += d * 0.6
        else:
            if ratio < 3.0:
                priority = (ratio - 2) ** 4 * 120 + 80
                for e in range(1, 6):
                    priority += np.exp(-ratio * e) * np.cos(np.pi * e * ratio / 3) * (e * 3)
                if capacity % 4 == 0:
                    priority += 5.5
                elif capacity % 6 == 0:
                    priority += 4.1
                else:
                    priority += 2.2
            else:
                priority = np.inf
        priorities[i] = priority
    return priorities
